#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e4+5;
int n,s,a[maxn],f[maxn][maxn]= {1};
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>s;
	for(int i=1; i<=n; i++) cin>>a[i];
	for(int i=1; i<=n; i++) {
		for(int j=a[i]; j<=s; j++) {
			f[i][j]=f[i-1][j];
			if(j>=a[i]) f[i][j]+=f[i-1][j-a[i]];
		}
	}
	cout<<f[n][s];
	return 0;
}
